#include <stdio.h>
#include <string.h>
#include <stdbool.h>

int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int n; scanf("%d", &n);
        char words[10][21];
        for (int i = 0; i < n; ++i) scanf("%20s", words[i]);
        // find shortest word index
        int minIdx = 0;
        for (int i = 1; i < n; ++i) if (strlen(words[i]) < strlen(words[minIdx])) minIdx = i;
        char *shortest = words[minIdx];
        int L = strlen(shortest);
        char best[21] = "";
        int bestLen = 0;
        for (int i = 0; i < L; ++i) {
            for (int len = 1; i + len <= L; ++len) {
                char sub[21];
                memcpy(sub, shortest + i, len);
                sub[len] = '\0';
                bool ok = true;
                for (int j = 0; j < n && ok; ++j) if (j != minIdx) {
                    if (strstr(words[j], sub) == NULL) ok = false;
                }
                if (ok) {
                    if (len > bestLen || (len == bestLen && strcmp(sub, best) < 0)) {
                        bestLen = len;
                        strcpy(best, sub);
                    }
                }
            }
        }
        printf("%s\n", best);
    }
    return 0;
}

