    while (T--) {
        int n; cin >> n;
        vector<string> w(n);
        for (int i = 0; i < n; ++i) cin >> w[i];
        // shortest word
        int idx = min_element(w.begin(), w.end(), [](const string &a, const string &b){ return a.size() < b.size(); }) - w.begin();
        const string &s = w[idx];
        string best = "";
        int L = s.size();
        for (int i = 0; i < L; ++i) {
            for (int len = 1; i + len <= L; ++len) {
                string sub = s.substr(i, len);
                bool ok = true;
                for (int j = 0; j < n && ok; ++j) if (j != idx) {
                    if (w[j].find(sub) == string::npos) ok = false;
                }
                if (ok) {
                    if ((int)sub.size() > (int)best.size() || ((int)sub.size() == (int)best.size() && sub < best))
                        best = sub;
                }
            }
        }
        cout << best << '\n';
    }
    return 0;
}

