import java.io.*;
import java.util.*;
public class Main {
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringBuilder out = new StringBuilder();
        int T = Integer.parseInt(br.readLine().trim());
        while (T-- > 0) {
            int n = Integer.parseInt(br.readLine().trim());
            String[] parts = br.readLine().trim().split(" ");
            String[] w = parts;
            int minIdx = 0;
            for (int i = 1; i < n; i++) if (w[i].length() < w[minIdx].length()) minIdx = i;
            String shortest = w[minIdx];
            String best = "";
            int L = shortest.length();
            for (int i = 0; i < L; i++) {
                for (int len = 1; i + len <= L; len++) {
                    String sub = shortest.substring(i, i + len);
                    boolean ok = true;
                    for (int j = 0; j < n && ok; j++) if (j != minIdx) {
                        if (!w[j].contains(sub)) ok = false;
                    }
                    if (ok) {
                        if (sub.length() > best.length() || (sub.length() == best.length() && sub.compareTo(best) < 0)) {
                            best = sub;
                        }
                    }
                }
            }
            out.append(best).append('\n');
        }
        System.out.print(out.toString());
    }
}

