#!/usr/bin/env python3
import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        n = int(next(it))
        words = [next(it) for _ in range(n)]
        shortest = min(words, key=len)
        best = ""
        L = len(shortest)
        for i in range(L):
            for l in range(1, L - i + 1):
                sub = shortest[i:i+l]
                if all(sub in w for w in words):
                    if l > len(best) or (l == len(best) and sub < best):
                        best = sub
        out_lines.append(best)
    sys.stdout.write("\n".join(out_lines))

if __name__ == "__main__":
    solve()

